const cfg = $input.first().json;
const now = Date.now();
const items = [];

const addCases = (scenario, count, extra = {}) => {
  for (let i = 0; i < Number(count || 0); i++) {
    items.push({
      json: {
        webhook_url: cfg.webhook_url,
        mock_base_url: cfg.mock_base_url,
        channel: cfg.channel || 'EMAIL',
        scenario,
        transaction_id: `tx-${scenario}-${now}-${String(i + 1).padStart(3, '0')}`,
        citizen_id: `citizen-${String(i + 1).padStart(3, '0')}`,
        document_number: `10${String(20000000 + i)}`,
        incident_description: `Denuncia digital de prueba - ${scenario}`,
        incident_address: 'Carrera 7 # 12-34, Bogotá D.C.',
        incident_category: cfg.incident_category || 'HURTO',
        municipality_code: '11001',
        requested_scope: 'denuncia.write denuncia.read',
        verification_mode: cfg.verification_mode || 'document',
        force_auth_reject: false,
        force_invalid_identity: false,
        force_georef_reject: false,
        force_policia_reject: false,
        force_fiscalia_reject: false,
        force_notify_reject: false,
        delay_ms: 0,
        jitter_ms: 0,
        ...extra,
      },
    });
  }
};

addCases('success', cfg.success_count);
addCases('auth_denied', cfg.auth_denied_count, {
  force_auth_reject: true,
});
addCases('invalid_identity', cfg.invalid_identity_count, {
  force_invalid_identity: true,
});
addCases('georef_reject', cfg.georef_reject_count, {
  force_georef_reject: true,
});
addCases('policia_reject', cfg.policia_reject_count, {
  force_policia_reject: true,
});
addCases('fiscalia_reject', cfg.fiscalia_reject_count, {
  force_fiscalia_reject: true,
});
addCases('notify_reject', cfg.notify_reject_count, {
  force_notify_reject: true,
});
addCases('latency_simulated', cfg.latency_count, {
  delay_ms: Number(cfg.delay_ms || 250),
  jitter_ms: Number(cfg.jitter_ms || 75),
});

return items;

const rows = $input.all().map(item => item.json);
const byStatus = {};
const byReason = {};

for (const row of rows) {
  const status = row.status || 'unknown';
  const reason = row.fail_reason || '(none)';
  byStatus[status] = (byStatus[status] || 0) + 1;
  byReason[reason] = (byReason[reason] || 0) + 1;
}

return [
  {
    json: {
      total_requests: rows.length,
      by_status: byStatus,
      by_fail_reason: byReason,
      sample: rows.slice(0, 5),
    },
  },
];
